Code.NativeIaC:
```bicep
// Bicep: MySQL Flexible Server with zone-redundant high availability
resource mysql 'Microsoft.DBforMySQL/flexibleServers@2023-12-30' = {
  name: '<example_resource_name>'
  location: '<region>'
  sku: {
    name: 'Standard_D2ds_v4'
    tier: 'GeneralPurpose'
  }
  properties: {
    highAvailability: {
      mode: 'ZoneRedundant' // CRITICAL: provisions a standby replica with automatic failover
    }
  }
}
```

Code.Terraform:
```hcl
# Terraform: MySQL Flexible Server with zone-redundant high availability
resource "azurerm_mysql_flexible_server" "<example_resource_name>" {
  name                = "<example_resource_name>"
  resource_group_name = "<example_resource_name>"
  location            = "<region>"
  sku_name            = "GP_Standard_D2ds_v4"

  high_availability {
    mode = "ZoneRedundant" # CRITICAL: provisions a standby replica with automatic failover
  }
}
```
